CREATE MODEL review_detailed(
    reviews
) ENGINE = OpenAI(api_key = 'sk-proj-xxx', model_name = 'gpt-3.5-turbo')
PROMPT customer_review_pt_detailed;

select page, block_type, count(block_type) from pdf_blocks_billionaires 
    where block_type like 'LAYOUT%' 
    group by page, block_type;

INSERT INTO pdfs(content, metadata)
SELECT content, metadata from 
load_pdf_text ('https://d18rn0p25nwr6d.cloudfront.net/CIK-0000320193/faab4555-c69b-438a-aaf7-e09305f87ca3.pdf');

CREATE TABLE pdf_embeddings (
  id UUID,
  embeddings `Array`(`Float32`)
) 
engine = MergeTree
order by id;

CREATE TABLE pdf_links
(
    link `String`
) engine = MergeTree
order by link;

CREATE MODEL retrieval_evaluator (
    question,
    document
) ENGINE = OpenAI(api_key = 'sk-proj-xxx', model_name = 'gpt-3.5-turbo')
PROMPT ( system "
Given a question, does the following document have exact
information to answer the question?
Question: {{question}}
Document: {{document}}
Think Step by step, and answer with yes or no only");

CREATE ENDPOINT get_correct_documents(question String) AS 
 (with tbl as (
    select id, content, retrieval_evaluator($question, content) answer from pdf_contents
)
select id, answer, content
from tbl where positionCaseInsensitive(answer, 'yes') > 0)
COMMENT 'Endpoint to get the relevant document to the question';

CREATE MODEL evaluator(
    question,
    answer,
    score
) ENGINE = OpenAI(api_key = 'sk-proj-xxx', model_name = 'gpt-3.5-turbo')
PROMPT (system "Given a question and possible answer respond if it is relevant or not. 
Answer 'yes' if the score is below 0.1. If score is not provided, return 'no'.
Please use 'yes' or 'no' as the answer. 
question: {{question}}
possible answer: {{answer}}
similarity score: {{score}}");

CREATE ENDPOINT retrieval_evaluator(question String, document String) AS
(SELECT retrieval_evaluator($question, $document))
COMMENT 'Endpoint for evaluating the relevancy of an question and document';

CREATE ENDPOINT fallback_model(question String) AS
(SELECT fallback_model($question))
COMMENT 'Endpoint for searching fallback data source';

CREATE TABLE pdf_links (
	`city` String,
	`link` String
) engine = MergeTree
order by city;

INSERT INTO pdfs(content, metadata, city) 
SELECT content, metadata, JSONExtractString(metadata,'city')
FROM load_pdf_text((SELECT link, city from pdf_links));

CREATE TABLE pdf_embeddings (
  id UUID,
  embeddings `Array`(`Float32`),
) 
engine = MergeTree
order by id;

CREATE ENDPOINT get_semantics() AS 
(SELECT * FROM semantics())
COMMENT 'Schemas of all the tables';

CREATE MODEL IF NOT EXISTS cities_info_model( 
    input
) ENGINE = OpenAI(api_key = 'sk-proj-xxx', model_name = 'gpt-3.5-turbo')
PROMPT cities_prompt
TOOLS (langdb_raw_query);

CREATE TABLE products (
    product_id UInt32,
    product_name String
) ENGINE = MergeTree
ORDER BY product_id;

CREATE PROMPT customer_review_pt (
  system "You are an AI assistant. Look at the provided review and return average sentiment score for the review.
    Strictly only return a number between 1 and 5 as a value without any description.
    ",
  human "{{review}}"
);

CREATE MODEL review(
    review
) ENGINE = OpenAI(api_key = 'sk-proj-xxx', model_name = 'gpt-3.5-turbo')
PROMPT customer_review_pt;
